fn ensure_run_graph_dispatch_receipt_summary_consistency(
    receipt: &RunGraphDispatchReceiptStored,
) -> Result<(), StateStoreError> {
    if receipt.dispatch_status.trim().is_empty() {
        return Err(StateStoreError::InvalidTaskRecord {
            reason: format!(
                "run-graph dispatch receipt summary is inconsistent for `{}`: dispatch_status must be non-empty",
                receipt.run_id
            ),
        });
    }
    let Some(raw_lane_status) = receipt.lane_status.as_deref() else {
        return Ok(());
    };
    if raw_lane_status.trim().is_empty() {
        return Err(StateStoreError::InvalidTaskRecord {
            reason: format!(
                "run-graph dispatch receipt summary is inconsistent for `{}`: lane_status must be non-empty when present",
                receipt.run_id
            ),
        });
    }
    let raw_lane_status = raw_lane_status.trim();
    let canonical_lane_status =
        canonical_lane_status_str(raw_lane_status).unwrap_or(raw_lane_status);
    let downstream_closure_completed = receipt.downstream_dispatch_status.as_deref()
        == Some("executed")
        && canonical_lane_status == "lane_completed";
    let effective_derived_lane_status = if downstream_closure_completed {
        "lane_completed".to_string()
    } else {
        normalize_run_graph_lane_status(
            Some(raw_lane_status),
            &receipt.dispatch_status,
            receipt.supersedes_receipt_id.as_deref(),
            receipt.exception_path_receipt_id.as_deref(),
        )
    };
    if receipt.downstream_dispatch_status.is_some()
        && canonical_lane_status != effective_derived_lane_status
    {
        return Err(StateStoreError::InvalidTaskRecord {
            reason: format!(
                "run-graph dispatch receipt summary is inconsistent for `{}`: downstream_dispatch_status `{}` with lane_status `{}` conflicts with derived lane_status `{}` from dispatch_status `{}`",
                receipt.run_id,
                receipt
                    .downstream_dispatch_status
                    .as_deref()
                    .unwrap_or("none"),
                canonical_lane_status,

pub(crate) fn validate_run_graph_resume_gate(status: &RunGraphStatus) -> Result<(), String> {
    if !status.recovery_ready {
        return Err(format!(
            "Run-graph resume gate denied for `{}`: recovery_ready is false",
            status.run_id
        ));
    }
    if status.resume_target == "none" || !status.resume_target.starts_with("dispatch.") {
        return Err(format!(
            "Run-graph resume gate denied for `{}`: resume_target `{}` is not a dispatch target",
            status.run_id, status.resume_target
        ));
    }
    ensure_resume_target_handoff_consistency(status).map_err(|error| {
        format!(
            "Run-graph resume gate denied for `{}`: {error}",
            status.run_id
        )
    })?;
    if !is_dispatch_resume_handoff_complete(status) {
        return Err(format!(
            "Run-graph resume gate denied for `{}`: dispatch resume target `{}` requires complete handoff metadata (next_node={}, policy_gate=`{}`, handoff=`{}`)",
            status.run_id,
            status.resume_target,
            status.next_node.as_deref().unwrap_or("none"),
            status.policy_gate,
            status.handoff_state
        ));
    }
    if !status.delegation_gate().delegated_cycle_open {
        return Err(format!(
            "Run-graph resume gate denied for `{}`: delegated cycle is not open",
            status.run_id
        ));
    }
    Ok(())
}
fn resume_dispatch_node(resume_target: &str) -> Option<&str> {
    let resume_target = resume_target.trim();
    let stripped = resume_target.strip_prefix("dispatch.")?;
    let node = stripped.strip_suffix("_lane").unwrap_or(stripped);
    if node.is_empty() {
        return None;
    }
    Some(node)
}

fn ensure_resume_target_handoff_consistency(status: &RunGraphStatus) -> Result<(), String> {
    if let Some(node) = resume_dispatch_node(&status.resume_target) {
        let expected_handoff = format!("awaiting_{node}");
        if status.handoff_state != expected_handoff {
            return Err(format!(
                "run-graph resume metadata inconsistent for `{}`: resume_target `{}` requires handoff_state `{}`, not `{}`",
                status.run_id, status.resume_target, expected_handoff, status.handoff_state
            ));
        }
        if status.next_node.as_deref() != Some(node) {
            return Err(format!(
                "run-graph resume metadata inconsistent for `{}`: resume_target `{}` requires next_node `{}`",
                status.run_id, status.resume_target, node
            ));
        }
    } else if status.handoff_state.starts_with("awaiting_") {
        return Err(format!(
            "run-graph resume metadata inconsistent for `{}`: handoff_state `{}` requires a dispatch.* resume_target",
            status.run_id, status.handoff_state
        ));
    }
    Ok(())
}

fn canonicalize_resume_meta(status: &mut RunGraphStatus) {
    if let Some(node) = resume_dispatch_node(&status.resume_target) {
        status.next_node = Some(node.to_string());
        status.handoff_state = format!("awaiting_{node}");
    } else {
        status.next_node = None;
        status.handoff_state = "none".to_string();
    }
}

fn meta_string_field(meta: &serde_json::Value, key: &str) -> Option<Option<String>> {
    meta.get(key)?;
    Some(
        meta.get(key)
            .and_then(|value| value.as_str())
            .map(ToOwned::to_owned),
    )
}

pub(crate) fn merge_run_graph_meta(

    let explicit_continuation_binding = store
        .run_graph_continuation_binding(&status.run_id)
        .await
        .map_err(|error| format!("Failed to read explicit continuation binding: {error}"))?;
    let latest_run_graph_recovery = store
        .latest_run_graph_recovery_summary()
        .await
        .map_err(|error| format!("Failed to read latest run graph recovery summary: {error}"))?;
    let latest_run_graph_dispatch_receipt =
        match store.latest_run_graph_dispatch_receipt_summary().await {
            Ok(summary) => summary,
            Err(_) => None,
        };
    let continuation_binding_evidence_ambiguous = latest_run_graph_dispatch_receipt
        .as_ref()
        .is_some_and(|receipt| {
            crate::state_store::latest_run_graph_dispatch_receipt_signal_is_ambiguous(receipt)
                || crate::state_store::latest_run_graph_dispatch_receipt_summary_is_inconsistent(
                    Some(status.run_id.as_str()),
                    Some(receipt.run_id.as_str()),
                )
        });
    let continuation_binding =
        crate::continuation_binding_summary::build_continuation_binding_summary(
            explicit_continuation_binding.as_ref(),
            Some(&status),
            latest_run_graph_recovery.as_ref(),
            latest_run_graph_dispatch_receipt.as_ref(),
            continuation_binding_evidence_ambiguous,
        );
    if continuation_binding["status"] != "bound" {
        return Err(format!(
            "Latest continuation binding for run `{}` is ambiguous. Either bind the next bounded unit explicitly with `vida taskflow continuation bind {} --task-id <task-id> --json` or pass `--run-id {}` to refresh that specific run.",
            status.run_id, status.run_id, status.run_id
        ));
    }
    if status.status == "completed"
        && continuation_binding["active_bounded_unit"]["kind"] != "downstream_dispatch_target"
    {
        let unit_kind = continuation_binding["active_bounded_unit"]["kind"]
            .as_str()
            .unwrap_or("unknown");
        return Err(format!(
            "Latest continuation binding for run `{}` points to `{unit_kind}`, which is not resumeable through default `vida taskflow consume continue --json`. Pass `--run-id {}` to refresh the completed run explicitly or bind/shape the next bounded unit before continuing.",
            status.run_id, status.run_id
        ));
    }
    Ok(status.run_id)
}

